"""
National ID (Fayda) integration service with circuit breaker and simulation mode.
"""
from __future__ import annotations
import logging
import random
import string
import time
from datetime import datetime

from django.conf import settings

logger = logging.getLogger(__name__)


class NationalIDServiceError(Exception):
    pass


class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=60):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.failure_count = 0
        self.last_failure_time = None
        self.state = 'CLOSED'

    def call(self, func, *args, **kwargs):
        if self.state == 'OPEN':
            if time.time() - self.last_failure_time > self.recovery_timeout:
                self.state = 'HALF_OPEN'
            else:
                raise NationalIDServiceError("Service temporarily unavailable (circuit open)")
        try:
            result = func(*args, **kwargs)
            if self.state == 'HALF_OPEN':
                self.state = 'CLOSED'
                self.failure_count = 0
            return result
        except Exception as exc:
            self.failure_count += 1
            self.last_failure_time = time.time()
            if self.failure_count >= self.failure_threshold:
                self.state = 'OPEN'
            raise


class NationalIDService:
    _circuit_breaker = CircuitBreaker()

    def __init__(self):
        nid_settings = getattr(settings, 'NATIONAL_ID_SERVICE', {})
        self.simulation_mode = nid_settings.get('SIMULATION_MODE', True)
        self.api_base_url = nid_settings.get('API_BASE_URL', 'https://api.fayda.et')
        self.api_key = nid_settings.get('API_KEY', '')
        self.timeout = nid_settings.get('TIMEOUT', 30)

    def initiate_verification(self, national_id: str) -> dict:
        if self.simulation_mode:
            return self._simulate_initiate(national_id)
        return self._circuit_breaker.call(self._real_initiate, national_id)

    def verify_otp(self, national_id: str, otp: str) -> dict:
        if self.simulation_mode:
            return self._simulate_verify_otp(national_id, otp)
        return self._circuit_breaker.call(self._real_verify_otp, national_id, otp)

    def get_profile(self, national_id: str) -> dict:
        if self.simulation_mode:
            return self._simulate_get_profile(national_id)
        return self._circuit_breaker.call(self._real_get_profile, national_id)

    def _simulate_initiate(self, national_id: str) -> dict:
        logger.info("[NID SIMULATION] Initiate verification for %s", national_id)
        otp = ''.join(random.choices(string.digits, k=6))
        phone_suffix = national_id[-4:] if len(national_id) >= 4 else '0000'
        phone_number = f"+2519{phone_suffix}0000"
        logger.info("[NID SIMULATION] OTP for %s: %s", national_id, otp)
        return {
            'success': True,
            'phone_number': phone_number,
            'simulation_mode': True,
            'simulation_otp': otp,
            'transaction_id': f"SIM-{national_id}-{int(time.time())}",
        }

    def _simulate_verify_otp(self, national_id: str, otp: str) -> dict:
        logger.info("[NID SIMULATION] Verify OTP for %s", national_id)
        return {
            'success': True,
            'verified': True,
            'transaction_id': f"SIM-VERIFY-{national_id}-{int(time.time())}",
        }

    def _simulate_get_profile(self, national_id: str) -> dict:
        logger.info("[NID SIMULATION] Get profile for %s", national_id)
        first_names = ['Abebe', 'Kebede', 'Tigist', 'Alemitu', 'Yonas', 'Hanna', 'Samuel', 'Meron']
        last_names = ['Bekele', 'Haile', 'Girma', 'Tadesse', 'Alemu', 'Desta', 'Worku']
        full_name = f"{random.choice(first_names)} {random.choice(last_names)}"
        return {
            'fayda_sub': f"NID_{national_id}",
            'fin': national_id,
            'full_name': full_name,
            'dob': '1990-01-01',
            'gender': random.choice(['Male', 'Female']),
            'address': 'Addis Ababa, Ethiopia',
            'phone': f"+2519{national_id[-4:] if len(national_id) >= 4 else '0000'}0000",
            'photo': None,
            'simulation_mode': True,
        }

    def _real_initiate(self, national_id: str) -> dict:
        import requests
        try:
            response = requests.post(
                f"{self.api_base_url}/verify/initiate",
                json={"national_id": national_id},
                headers={"Authorization": f"Bearer {self.api_key}"},
                timeout=self.timeout,
            )
            response.raise_for_status()
            return response.json()
        except requests.RequestException as exc:
            logger.error("NID initiate error: %s", exc)
            raise NationalIDServiceError(f"NID service error: {exc}") from exc

    def _real_verify_otp(self, national_id: str, otp: str) -> dict:
        import requests
        try:
            response = requests.post(
                f"{self.api_base_url}/verify/otp",
                json={"national_id": national_id, "otp": otp},
                headers={"Authorization": f"Bearer {self.api_key}"},
                timeout=self.timeout,
            )
            response.raise_for_status()
            return response.json()
        except requests.RequestException as exc:
            logger.error("NID verify OTP error: %s", exc)
            raise NationalIDServiceError(f"NID service error: {exc}") from exc

    def _real_get_profile(self, national_id: str) -> dict:
        import requests
        try:
            response = requests.get(
                f"{self.api_base_url}/profile/{national_id}",
                headers={"Authorization": f"Bearer {self.api_key}"},
                timeout=self.timeout,
            )
            response.raise_for_status()
            return response.json()
        except requests.RequestException as exc:
            logger.error("NID get profile error: %s", exc)
            raise NationalIDServiceError(f"NID service error: {exc}") from exc
