/**
 * Mock Organization Member Verification API
 * ─────────────────────────────────────────
 * Simulates a real organization's member database API so you can test the
 * CredWallet platform's federated issuance integration locally.
 *
 * Start: cd mock_org_api && npm install && npm start
 * URL:   http://localhost:3001
 */
'use strict';

const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3001;
const API_KEY = process.env.API_KEY || 'mock-api-key-for-testing';

app.use(express.json());

// Load member database
const members = JSON.parse(
  fs.readFileSync(path.join(__dirname, 'members.json'), 'utf8')
);

// ─── Middleware ───────────────────────────────────────────────────────────────

function authenticate(req, res, next) {
  const key = req.headers['x-api-key'] || req.headers['authorization']?.replace('Bearer ', '');
  if (!key || key !== API_KEY) {
    return res.status(401).json({ error: 'Unauthorized: invalid or missing API key' });
  }
  next();
}

function requestLogger(req, res, next) {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`, req.body || '');
  next();
}

app.use(requestLogger);

// ─── Routes ───────────────────────────────────────────────────────────────────

// Health check — no auth required
app.get('/health', (req, res) => {
  res.json({ status: 'ok', service: 'Mock Org Member API', version: '1.0.0' });
});

// List all members (admin convenience, no auth in mock)
app.get('/api/members', (req, res) => {
  const safeMembers = members.map(({ secret, ...m }) => m);
  res.json({ count: safeMembers.length, members: safeMembers });
});

/**
 * POST /api/members/verify
 *
 * Accepts: { member_id: "<national-id or membership-number>" }
 * Returns: { is_eligible: bool, member: {...} } or { is_eligible: false, reason: "..." }
 */
app.post('/api/members/verify', authenticate, (req, res) => {
  const memberId = req.body?.member_id || req.body?.national_id || req.body?.identifier;

  if (!memberId) {
    return res.status(400).json({
      is_eligible: false,
      reason: 'member_id field is required in request body',
    });
  }

  const member = members.find(
    (m) =>
      m.national_id === memberId ||
      m.membership_number === memberId ||
      m.email === memberId
  );

  if (!member) {
    return res.json({
      is_eligible: false,
      reason: `No member found with identifier: ${memberId}`,
    });
  }

  if (member.status !== 'active') {
    return res.json({
      is_eligible: false,
      reason: `Member account is ${member.status} — cannot issue credentials`,
    });
  }

  // Return eligibility + structured member data
  return res.json({
    is_eligible: true,
    member: {
      full_name: member.full_name,
      student_id: member.membership_number,
      email: member.email,
      phone: member.phone || null,
      programme: member.programme || null,
      year: member.year || null,
      department: member.department || null,
      national_id: member.national_id,
      status: member.status,
      enrollment_date: member.enrollment_date || null,
      graduation_year: member.graduation_year || null,
    },
  });
});

/**
 * POST /api/members/verify-extended
 *
 * Same as /verify but with additional nested data for testing dot-notation mapping.
 */
app.post('/api/members/verify-extended', authenticate, (req, res) => {
  const memberId = req.body?.member_id;
  const member = members.find((m) => m.national_id === memberId);

  if (!member || member.status !== 'active') {
    return res.json({ is_eligible: false, reason: 'Member not found or inactive' });
  }

  return res.json({
    is_eligible: true,
    data: {
      personal: {
        full_name: member.full_name,
        national_id: member.national_id,
        email: member.email,
      },
      academic: {
        programme: member.programme,
        year: member.year,
        department: member.department,
        gpa: member.gpa || null,
      },
      membership: {
        number: member.membership_number,
        status: member.status,
        enrolled_at: member.enrollment_date,
      },
    },
  });
});

// ─── Error handling ────────────────────────────────────────────────────────────

app.use((req, res) => {
  res.status(404).json({ error: `Route not found: ${req.method} ${req.path}` });
});

app.use((err, req, res, next) => {
  console.error('[ERROR]', err.message);
  res.status(500).json({ error: 'Internal server error', details: err.message });
});

// ─── Start ────────────────────────────────────────────────────────────────────

app.listen(PORT, () => {
  console.log(`\n✅ Mock Org API running at http://localhost:${PORT}`);
  console.log(`   API Key: ${API_KEY}`);
  console.log(`   Members: ${members.length}`);
  console.log('\nEndpoints:');
  console.log(`   GET  /health`);
  console.log(`   GET  /api/members              (list all, no auth)`);
  console.log(`   POST /api/members/verify       (verify member, requires X-API-Key)`);
  console.log(`   POST /api/members/verify-extended  (nested response for dot-notation testing)`);
  console.log('\nTo verify a member:');
  console.log(`   curl -X POST http://localhost:${PORT}/api/members/verify \\`);
  console.log(`     -H 'Content-Type: application/json' \\`);
  console.log(`     -H 'X-API-Key: ${API_KEY}' \\`);
  console.log(`     -d '{"member_id":"NID-1234567890"}'`);
  console.log('');
});
