"""
FaydaNationalIDProvider — Real Fayda eKYC API integration.

Configuration (Django settings):
    NATIONAL_ID_SERVICE = {
        'API_BASE_URL': 'https://api.fayda.et',
        'API_KEY':      '<secret>',
        'TIMEOUT':      30,
    }

Production activation:
    Set DJANGO_ENV=production OR NID_SIMULATION_MODE=False
    in the environment to activate this provider.
"""
from __future__ import annotations

import logging
import time

from .base import NationalIdentityProvider, NIDProfile, NIDResult

logger = logging.getLogger(__name__)


class _CircuitBreaker:
    """Simple in-process circuit breaker for external API calls."""

    def __init__(self, failure_threshold: int = 5, recovery_timeout: int = 60):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.failure_count = 0
        self.last_failure_time: float | None = None
        self.state = "CLOSED"

    def call(self, func, *args, **kwargs):
        if self.state == "OPEN":
            elapsed = time.time() - (self.last_failure_time or 0)
            if elapsed > self.recovery_timeout:
                self.state = "HALF_OPEN"
            else:
                raise RuntimeError("NID service temporarily unavailable (circuit open)")

        try:
            result = func(*args, **kwargs)
            if self.state == "HALF_OPEN":
                self.state = "CLOSED"
                self.failure_count = 0
            return result
        except Exception:
            self.failure_count += 1
            self.last_failure_time = time.time()
            if self.failure_count >= self.failure_threshold:
                self.state = "OPEN"
            raise


class FaydaNationalIDProvider(NationalIdentityProvider):
    """
    Real Fayda eKYC API provider with circuit-breaker protection.

    Falls back gracefully on network failures and logs all errors.
    """

    _circuit_breaker = _CircuitBreaker()

    def __init__(self, api_base_url: str, api_key: str, timeout: int = 30):
        self.api_base_url = api_base_url.rstrip("/")
        self.api_key = api_key
        self.timeout = timeout

    def initiate_verification(self, national_id: str) -> NIDResult:
        try:
            return self._circuit_breaker.call(self._real_initiate, national_id)
        except RuntimeError as exc:
            return NIDResult(success=False, error=str(exc))
        except Exception as exc:
            logger.error("[NID FAYDA] initiate_verification error: %s", exc)
            return NIDResult(success=False, error=f"NID service error: {exc}")

    def verify_otp(self, national_id: str, otp: str) -> NIDResult:
        try:
            return self._circuit_breaker.call(self._real_verify_otp, national_id, otp)
        except RuntimeError as exc:
            return NIDResult(success=False, error=str(exc))
        except Exception as exc:
            logger.error("[NID FAYDA] verify_otp error: %s", exc)
            return NIDResult(success=False, error=f"NID service error: {exc}")

    def get_profile(self, national_id: str) -> NIDProfile:
        try:
            return self._circuit_breaker.call(self._real_get_profile, national_id)
        except Exception as exc:
            logger.error("[NID FAYDA] get_profile error: %s", exc)
            raise RuntimeError(f"NID service error: {exc}") from exc

    def _headers(self) -> dict:
        return {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
        }

    def _real_initiate(self, national_id: str) -> NIDResult:
        import requests

        resp = requests.post(
            f"{self.api_base_url}/verify/initiate",
            json={"national_id": national_id},
            headers=self._headers(),
            timeout=self.timeout,
        )
        resp.raise_for_status()
        data = resp.json()
        return NIDResult(
            success=data.get("success", True),
            transaction_id=data.get("transaction_id", ""),
            phone_number=data.get("phone_number", ""),
            simulation_mode=False,
            raw=data,
        )

    def _real_verify_otp(self, national_id: str, otp: str) -> NIDResult:
        import requests

        resp = requests.post(
            f"{self.api_base_url}/verify/otp",
            json={"national_id": national_id, "otp": otp},
            headers=self._headers(),
            timeout=self.timeout,
        )
        resp.raise_for_status()
        data = resp.json()
        return NIDResult(
            success=data.get("success", True),
            verified=data.get("verified", True),
            transaction_id=data.get("transaction_id", ""),
            simulation_mode=False,
            raw=data,
        )

    def _real_get_profile(self, national_id: str) -> NIDProfile:
        import requests

        resp = requests.get(
            f"{self.api_base_url}/profile/{national_id}",
            headers=self._headers(),
            timeout=self.timeout,
        )
        resp.raise_for_status()
        data = resp.json()
        return NIDProfile(
            fayda_sub=data.get("fayda_sub", f"NID_{national_id}"),
            fin=data.get("fin", national_id),
            full_name=data.get("full_name", ""),
            dob=data.get("dob"),
            gender=data.get("gender"),
            address=data.get("address"),
            phone=data.get("phone"),
            photo=data.get("photo"),
            simulation_mode=False,
            raw=data,
        )

"""
NationalIDService — facade that delegates to the active NationalIdentityProvider.

Provider selection (evaluated at construction time):
  1. If DJANGO_ENV == 'production'  → FaydaNationalIDProvider (real API)
  2. If NID_SIMULATION_MODE=True    → MockNationalIDProvider
  3. Default                        → MockNationalIDProvider

Settings block (optional — all keys have safe defaults):
    NATIONAL_ID_SERVICE = {
        'API_BASE_URL': 'https://api.fayda.et',
        'API_KEY':      '',
        'TIMEOUT':      30,
        'SIMULATION_MODE': True,   # overrides env-based detection when present
    }
"""
from __future__ import annotations

import logging

from django.conf import settings

from national_id.services.providers import (
    FaydaNationalIDProvider,
    MockNationalIDProvider,
    NIDProfile,
    NIDResult,
)

logger = logging.getLogger(__name__)


class NationalIDServiceError(Exception):
    pass


class NationalIDService:
    """
    High-level facade for national identity operations.

    Raises NationalIDServiceError on any failure so callers don't need to
    handle provider-specific exceptions.
    """

    def __init__(self):
        self._provider = self._build_provider()

    def initiate_verification(self, national_id: str) -> dict:
        """
        Start an OTP-based verification session.

        Returns a dict compatible with the legacy API contract:
            {success, phone_number, simulation_mode?, simulation_otp?, transaction_id}
        """
        try:
            result: NIDResult = self._provider.initiate_verification(national_id)
        except Exception as exc:
            raise NationalIDServiceError(str(exc)) from exc

        if not result.success:
            raise NationalIDServiceError(result.error or "NID verification initiation failed")

        response = {
            "success": True,
            "phone_number": result.phone_number,
            "transaction_id": result.transaction_id,
        }
        if result.simulation_mode:
            response["simulation_mode"] = True
            response["simulation_otp"] = result.simulation_otp
        return response

    def verify_otp(self, national_id: str, otp: str) -> dict:
        """
        Confirm identity by submitting the OTP.

        Returns: {success, verified, transaction_id}
        """
        try:
            result: NIDResult = self._provider.verify_otp(national_id, otp)
        except Exception as exc:
            raise NationalIDServiceError(str(exc)) from exc

        if not result.success:
            raise NationalIDServiceError(result.error or "OTP verification failed")

        return {
            "success": True,
            "verified": result.verified,
            "transaction_id": result.transaction_id,
        }

    def get_profile(self, national_id: str) -> dict:
        """
        Fetch the citizen's full eKYC profile.

        Returns a dict with: fayda_sub, fin, full_name, dob, gender,
                             address, phone, photo, simulation_mode?
        """
        try:
            profile: NIDProfile = self._provider.get_profile(national_id)
        except Exception as exc:
            raise NationalIDServiceError(str(exc)) from exc

        data = {
            "fayda_sub": profile.fayda_sub,
            "fin": profile.fin,
            "full_name": profile.full_name,
            "dob": profile.dob,
            "gender": profile.gender,
            "address": profile.address,
            "phone": profile.phone,
            "photo": profile.photo,
        }
        if profile.simulation_mode:
            data["simulation_mode"] = True
        return data

    @property
    def is_simulation(self) -> bool:
        return self._provider.is_simulation

    def _build_provider(self):
        """Select and construct the appropriate identity provider."""
        nid_settings: dict = getattr(settings, "NATIONAL_ID_SERVICE", {})

        # Explicit override in settings takes highest precedence
        if "SIMULATION_MODE" in nid_settings:
            use_simulation = bool(nid_settings["SIMULATION_MODE"])
        else:
            environment = getattr(settings, "ENVIRONMENT", "development").lower()
            use_simulation = environment != "production"

        if use_simulation:
            logger.info("[NID] Using MockNationalIDProvider (simulation mode)")
            return MockNationalIDProvider()

        api_base_url = nid_settings.get("API_BASE_URL", "https://api.fayda.et")
        api_key = nid_settings.get("API_KEY", "")
        timeout = int(nid_settings.get("TIMEOUT", 30))

        if not api_key:
            logger.warning(
                "[NID] NATIONAL_ID_SERVICE.API_KEY is not configured — "
                "falling back to MockNationalIDProvider"
            )
            return MockNationalIDProvider()

        logger.info("[NID] Using FaydaNationalIDProvider (real API: %s)", api_base_url)
        return FaydaNationalIDProvider(
            api_base_url=api_base_url,
            api_key=api_key,
            timeout=timeout,
        )

