 * All three share the same API-key authentication model.
 *
 * Start: cd mock_org_api && npm install && npm start
 * URL:   http://localhost:3001
 *
 * Endpoints:
 *   GET  /health
 *   GET  /api/members                          (legacy — university members, no auth)
 *   POST /api/members/verify                   (legacy — university, requires X-API-Key)
 *   POST /api/members/verify-extended          (legacy — university nested, requires X-API-Key)
 *
 *   POST /university/members/verify            (university member lookup)
 *   POST /government/records/verify            (civil servant record lookup)
 *   POST /employer/employees/verify            (employee record lookup)
 *
 *   GET  /university/members                   (list university members, no auth)
 *   GET  /government/records                   (list government records, no auth)
 *   GET  /employer/employees                   (list employer records, no auth)
 */
'use strict';

const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const PORT = process.env.PORT || 3001;
const API_KEY = process.env.API_KEY || 'mock-api-key-for-testing';

app.use(express.json());

// ─── Load databases ────────────────────────────────────────────────────────────

function loadDb(filename) {
  const legacyPath = path.join(__dirname, filename);
  const dataPath = path.join(__dirname, 'data', filename);
  const filePath = fs.existsSync(dataPath) ? dataPath : legacyPath;
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

const universityMembers = loadDb('university_members.json');
const governmentRecords = loadDb('government_records.json');
const employerRecords = loadDb('employer_records.json');

// Keep legacy members.json working if present
let legacyMembers = [];
try {
  legacyMembers = loadDb('members.json');
} catch (_) {
  legacyMembers = universityMembers;
}

// ─── Middleware ────────────────────────────────────────────────────────────────

function authenticate(req, res, next) {
  const key =
    req.headers['x-api-key'] ||
    req.headers['authorization']?.replace('Bearer ', '');
  if (!key || key !== API_KEY) {
    return res.status(401).json({ error: 'Unauthorized: invalid or missing API key' });
  }
  next();
}

function requestLogger(req, res, next) {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`, req.body || '');
  next();
}

app.use(requestLogger);

// ─── Helpers ──────────────────────────────────────────────────────────────────

function findByIdentifier(db, identifier) {
  if (!identifier) return null;
  return db.find(
    (r) =>
      r.national_id === identifier ||
      r.membership_number === identifier ||
      r.employee_id === identifier ||
      r.record_number === identifier ||
      r.email === identifier
  ) || null;
}

// ─── Global health ────────────────────────────────────────────────────────────

app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    service: 'Mock Multi-Org API',
    version: '2.0.0',
    organizations: {
      university: { members: universityMembers.length },
      government: { records: governmentRecords.length },
      employer: { employees: employerRecords.length },
    },
  });
});

// ─── UNIVERSITY endpoints ──────────────────────────────────────────────────────

app.get('/university/members', (req, res) => {
  res.json({ count: universityMembers.length, members: universityMembers });
});

/**
 * POST /university/members/verify
 * Body: { member_id: "<national_id | membership_number | email>" }
 */
app.post('/university/members/verify', authenticate, (req, res) => {
  const identifier =
    req.body?.member_id || req.body?.national_id || req.body?.identifier;

  if (!identifier) {
    return res.status(400).json({ is_eligible: false, reason: 'member_id is required' });
  }

  const member = findByIdentifier(universityMembers, identifier);

  if (!member) {
    return res.json({ is_eligible: false, reason: `No student found: ${identifier}` });
  }

  if (member.status !== 'active') {
    return res.json({
      is_eligible: false,
      reason: `Student account is ${member.status}`,
    });
  }

  return res.json({
    is_eligible: true,
    member: {
      full_name: member.full_name,
      student_id: member.membership_number,
      email: member.email,
      phone: member.phone || null,
      programme: member.programme,
      year: member.year,
      department: member.department,
      national_id: member.national_id,
      status: member.status,
      enrollment_date: member.enrollment_date,
      graduation_year: member.graduation_year,
      gpa: member.gpa,
    },
  });
});

/**
 * POST /university/members/verify-extended
 * Nested response for dot-notation field mapping tests.
 */
app.post('/university/members/verify-extended', authenticate, (req, res) => {
  const identifier = req.body?.member_id || req.body?.national_id;
  const member = findByIdentifier(universityMembers, identifier);

  if (!member || member.status !== 'active') {
    return res.json({ is_eligible: false, reason: 'Student not found or inactive' });
  }

  return res.json({
    is_eligible: true,
    data: {
      personal: {
        full_name: member.full_name,
        national_id: member.national_id,
        email: member.email,
        phone: member.phone,
      },
      academic: {
