def _get_access_token(self, data: dict) -> str | None:
    """Extract access token from login response regardless of nesting."""
    for key in ("access", "access_token", "token"):
        val = data.get(key)
        if val and isinstance(val, str):
            return val
    for nest_key in ("tokens", "token"):
        nested = data.get(nest_key, {})
        if isinstance(nested, dict):
            for key in ("access", "access_token"):
                if key in nested:
                    return nested[key]
    return None

